package com.example.demo.controller;
import com.example.demo.dto.*; import com.example.demo.entity.Order; import com.example.demo.service.SalesService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/orders") public class OrderController {private final SalesService service;public OrderController(SalesService service){this.service=service;}@PostMapping @ResponseStatus(HttpStatus.CREATED) public Order create(@RequestHeader("Authorization")String auth,@RequestBody CheckoutRequest r){return service.checkout(auth,r);}@GetMapping public List<Order> list(@RequestHeader("Authorization")String auth){return service.orders(auth);}@PatchMapping("/{id}/status") public Order status(@RequestHeader("Authorization")String auth,@PathVariable long id,@RequestBody StatusRequest r){return service.changeOrder(auth,id,r);}@PatchMapping("/{id}/cancel") public Order cancel(@RequestHeader("Authorization")String auth,@PathVariable long id){return service.cancelOrder(auth,id);}}
